// MARK: - UIApplication Helpers

extension UIApplication {

    static func topMostViewController(in windowScene: UIWindowScene? = nil) -> UIViewController? {
        let root: UIViewController? = {
            if let windowScene {
                return windowScene.windows.first(where: { $0.isKeyWindow })?.rootViewController
            } else {
                return UIApplication.shared.connectedScenes
                    .compactMap { $0 as? UIWindowScene }
                    .flatMap { $0.windows }
                    .first(where: { $0.isKeyWindow })?
                    .rootViewController
            }
        }()

        return topMost(from: root)
    }

    private static func topMost(from vc: UIViewController?) -> UIViewController? {
        guard let vc else { return nil }

        if let presented = vc.presentedViewController {
            return topMost(from: presented)
        }

        if let nav = vc as? UINavigationController {
            return topMost(from: nav.visibleViewController ?? nav.topViewController)
        }

        if let tab = vc as? UITabBarController {
            return topMost(from: tab.selectedViewController)
        }

        return vc
    }
}

